await spinner.show("Looking up definition...");
try {
  const result = await ai.prompt(
    `Define the word or phrase: "${selection.text}"

Provide:
1. Part of speech
2. Definition(s)
3. Example sentence(s)
4. Synonyms (if applicable)

Format the response in clean markdown.`,
    "You are a comprehensive dictionary. Provide clear, well-structured definitions."
  );
  await spinner.hide();
  await popup.markdown(`## 📖 ${selection.text}\n\n${result}`);
} catch (e) {
  await spinner.hide();
  await popup.error("Lookup failed: " + e.message);
}
